$ErrorActionPreference = "Stop"
$root = Get-Location
$stageRoot = Join-Path $root ".artifacts/agent-plugins"
$version = "1.0.0-rc.1"
$generatedAt = (Get-Date).ToUniversalTime().ToString("o")
$sourceCommit = (git rev-parse --short=12 HEAD).Trim()
$author = (git config user.name).Trim(); if([string]::IsNullOrWhiteSpace($author)){ $author="workspace-stakeholder" }

function Ensure-Dir([string]$path){ if(-not (Test-Path -LiteralPath $path)){ New-Item -ItemType Directory -Path $path -Force | Out-Null } }
function Copy-Asset([string]$src,[string]$dst){ Ensure-Dir (Split-Path -Parent $dst); Copy-Item -LiteralPath $src -Destination $dst -Recurse -Force }
function Rel([string]$base,[string]$target){ $b=[System.Uri]((Resolve-Path $base).Path.TrimEnd("\\") + [IO.Path]::DirectorySeparatorChar); $t=[System.Uri](Resolve-Path $target).Path; [System.Uri]::UnescapeDataString($b.MakeRelativeUri($t).ToString()).Replace("\\","/") }

$plugins = @(
  [ordered]@{ pluginId="PLG-01"; pluginName="core-intake-governance"; description="Deterministic intake, lifecycle governance, and cross-plugin control plane."; assets=[ordered]@{ agents=@("orchestrator.agent.md"); instructions=@("governance-lifecycle.instructions.md","request-economy.instructions.md","secure-coding.instructions.md","governance-release.instructions.md","governance-naming-conventions.instructions.md"); prompts=@("run-delivery-pattern.prompt.md","execute-delivery.prompt.md","review-project.prompt.md"); skills=@("work-intake-governance","route-customization","compose-skills","writing-plans","task-research","task-execution","plans","scope-change-control","taxonomy-tag-registry") }; purposes=[ordered]@{ "agents/orchestrator.agent.md"="Mandatory intake and routing authority for deterministic workflows."; "instructions/governance-lifecycle.instructions.md"="Defines lane controls and handoff traceability."; "instructions/request-economy.instructions.md"="Enforces bounded discovery and efficient operation."; "instructions/secure-coding.instructions.md"="Provides cross-cutting security defaults."; "instructions/governance-release.instructions.md"="Defines approval and release evidence policy."; "instructions/governance-naming-conventions.instructions.md"="Standardizes asset naming and discoverability conventions."; "prompts/run-delivery-pattern.prompt.md"="Encodes approved delivery pattern invocation."; "prompts/execute-delivery.prompt.md"="Supports controlled execution resumption."; "prompts/review-project.prompt.md"="Provides pre-execution review posture check."; "skills/work-intake-governance/SKILL.md"="Specializes intake classification and admission control."; "skills/route-customization/SKILL.md"="Maps requests to correct customization type."; "skills/compose-skills/SKILL.md"="Defines deterministic multi-skill composition contracts."; "skills/writing-plans/SKILL.md"="Produces execution-ready plans when absent."; "skills/task-research/SKILL.md"="Supports bounded research before implementation."; "skills/task-execution/SKILL.md"="Executes approved plans with traceability."; "skills/plans/SKILL.md"="Supports checkpointed plan execution in dedicated sessions."; "skills/scope-change-control/SKILL.md"="Governs adds, swaps, and descopes during delivery."; "skills/taxonomy-tag-registry/SKILL.md"="Maintains tag consistency across artifacts." } },
  [ordered]@{ pluginId="PLG-04"; pluginName="plugin-authoring-lifecycle"; description="End-to-end authoring and publishing workflows for agent plugins."; assets=[ordered]@{ agents=@("workspace-scaffolder.agent.md"); instructions=@("governance-naming-conventions.instructions.md","secure-coding.instructions.md","request-economy.instructions.md"); prompts=@("workspace-scaffolder.prompt.md"); skills=@("agent-plugin-setup","agent-plugin-design","agent-plugin-implementation-markdown","agent-plugin-implementation-extension","agent-plugin-tools-integration","agent-plugin-security-hardening","agent-plugin-publishing","agent-authoring","instructions-authoring","skills-authoring","route-customization","agent-plugin-integrity") }; purposes=[ordered]@{ "agents/workspace-scaffolder.agent.md"="Provides scaffolding specialization for new plugin and workspace setup."; "instructions/governance-naming-conventions.instructions.md"="Enforces naming standards for authored assets."; "instructions/secure-coding.instructions.md"="Applies security requirements to authoring and tool usage."; "instructions/request-economy.instructions.md"="Limits unnecessary request expansion and context use."; "prompts/workspace-scaffolder.prompt.md"="Operational prompt for scaffold execution flows."; "skills/agent-plugin-setup/SKILL.md"="Covers plugin skeleton and base manifest initialization."; "skills/agent-plugin-design/SKILL.md"="Defines persona, workflow, permissions, and boundaries."; "skills/agent-plugin-implementation-markdown/SKILL.md"="Implements simple .agent.md based agents."; "skills/agent-plugin-implementation-extension/SKILL.md"="Implements TypeScript extension-based agents."; "skills/agent-plugin-tools-integration/SKILL.md"="Handles built-in, MCP, and extension tool wiring."; "skills/agent-plugin-security-hardening/SKILL.md"="Performs hardening and threat-control checks."; "skills/agent-plugin-publishing/SKILL.md"="Defines packaging and publishing lifecycle."; "skills/agent-authoring/SKILL.md"="Improves .agent.md quality and role boundaries."; "skills/instructions-authoring/SKILL.md"="Improves instruction scope and applyTo quality."; "skills/skills-authoring/SKILL.md"="Improves skill trigger clarity and self-containment."; "skills/route-customization/SKILL.md"="Selects correct customization format per requirement."; "skills/agent-plugin-integrity/SKILL.md"="Produces deterministic per-file and bundle-level SHA-256 integrity evidence." } },
  [ordered]@{ pluginId="PLG-03"; pluginName="governance-review-audit"; description="Review-lane governance workflows for audits, findings, optimization, and release readiness decisions."; assets=[ordered]@{ agents=@("code-reviewer.agent.md","manual-code-reviewer.agent.md","governance-briefer.agent.md","powershell-reviewer.agent.md"); instructions=@("governance-lifecycle.instructions.md","technical-docs.instructions.md","task-implementation.instructions.md"); prompts=@("execute-customization-audit.prompt.md","governance-audit-types.prompt.md","governance-item-audit.prompt.md","audit-customization-types.prompt.md","audit-agent.prompt.md","optimize-customizations.prompt.md","execute-artifact-condense.prompt.md","execute-manual-review.prompt.md"); skills=@("governance-audit","execute-customization-audit","audit-executor","audit-customization-types","audit-agent","audit-instructions","audit-prompts","audit-skill","audit-powershell","acceptance-governance","optimize-customizations","governance-health-overview","governance-summarize","matrix-skill-mapping","delivery-status-grid","remediate-review","request-code-review","test-design-review","test-orchestration","release-readiness","release-simulation","post-release-retrospective") }; purposes=[ordered]@{ "agents/code-reviewer.agent.md"="Specialist for standards-based implementation review."; "agents/manual-code-reviewer.agent.md"="Captures structured manual review observations."; "agents/governance-briefer.agent.md"="Produces concise governance summaries from evidence."; "agents/powershell-reviewer.agent.md"="Reviews PowerShell assets for safety and maintainability."; "instructions/governance-lifecycle.instructions.md"="Governs lane ownership and handoff behavior."; "instructions/technical-docs.instructions.md"="Governs documentation quality and structure."; "instructions/task-implementation.instructions.md"="Governs plan-linked execution change traceability."; "prompts/execute-customization-audit.prompt.md"="Runs executive aggregate customization governance audits."; "prompts/governance-audit-types.prompt.md"="Runs deep type-level governance audits."; "prompts/governance-item-audit.prompt.md"="Runs focused single-item governance audit."; "prompts/audit-customization-types.prompt.md"="Executes deterministic cross-type interaction audits."; "prompts/audit-agent.prompt.md"="Executes agent-focused audit workflows."; "prompts/optimize-customizations.prompt.md"="Runs optimization-focused customization reviews."; "prompts/execute-artifact-condense.prompt.md"="Produces concise rewrite guidance for artifacts."; "prompts/execute-manual-review.prompt.md"="Applies and validates recorded manual review findings."; "skills/governance-audit/SKILL.md"="Baseline workspace governance assessment workflow."; "skills/execute-customization-audit/SKILL.md"="Aggregates governance outputs into executive disposition."; "skills/audit-executor/SKILL.md"="Coordinates full multi-type governance audit execution."; "skills/audit-customization-types/SKILL.md"="Evaluates customization type interactions and boundaries."; "skills/audit-agent/SKILL.md"="Evaluates .agent.md quality and invocation boundaries."; "skills/audit-instructions/SKILL.md"="Evaluates instruction integrity and applyTo correctness."; "skills/audit-prompts/SKILL.md"="Evaluates prompt execution contracts and safety."; "skills/audit-skill/SKILL.md"="Evaluates skill quality, triggers, and self-containment."; "skills/audit-powershell/SKILL.md"="Evaluates PowerShell script safety and style quality."; "skills/acceptance-governance/SKILL.md"="Evaluates outputs against acceptance criteria and sign-off rules."; "skills/optimize-customizations/SKILL.md"="Applies concise optimization checks across customization assets."; "skills/governance-health-overview/SKILL.md"="Synthesizes governance health into unified status view."; "skills/governance-summarize/SKILL.md"="Produces concise governance brief artifacts."; "skills/matrix-skill-mapping/SKILL.md"="Maintains matrix-to-skill coverage mapping integrity."; "skills/delivery-status-grid/SKILL.md"="Produces table-first delivery progress views."; "skills/remediate-review/SKILL.md"="Validates and applies review feedback rigorously."; "skills/request-code-review/SKILL.md"="Standardizes code-review request workflow."; "skills/test-design-review/SKILL.md"="Reviews test strategy and coverage rationale."; "skills/test-orchestration/SKILL.md"="Coordinates multi-discipline test evidence and outcomes."; "skills/release-readiness/SKILL.md"="Governs release gate evidence and promotion checks."; "skills/release-simulation/SKILL.md"="Supports pre-release rehearsal and rollback drill validation."; "skills/post-release-retrospective/SKILL.md"="Captures post-release outcomes and follow-up actions." } }
)

Ensure-Dir $stageRoot
$marketEntries = @()

foreach($p in $plugins){
  $pluginRoot = Join-Path $stageRoot (Join-Path $p.pluginName $version)
  if(Test-Path -LiteralPath $pluginRoot){ Remove-Item -LiteralPath $pluginRoot -Recurse -Force }
  Ensure-Dir $pluginRoot
  Ensure-Dir (Join-Path $pluginRoot "agents")
  Ensure-Dir (Join-Path $pluginRoot "instructions")
  Ensure-Dir (Join-Path $pluginRoot "prompts")
  Ensure-Dir (Join-Path $pluginRoot "skills")

  foreach($a in $p.assets.agents){ Copy-Asset (Join-Path $root ".github/agents/$a") (Join-Path $pluginRoot "agents/$a") }
  foreach($i in $p.assets.instructions){ Copy-Asset (Join-Path $root ".github/instructions/$i") (Join-Path $pluginRoot "instructions/$i") }
  foreach($pr in $p.assets.prompts){ Copy-Asset (Join-Path $root ".github/prompts/$pr") (Join-Path $pluginRoot "prompts/$pr") }
  foreach($s in $p.assets.skills){ Copy-Asset (Join-Path $root ".github/skills/$s") (Join-Path $pluginRoot "skills/$s") }

  $pluginJson = [ordered]@{ schemaVersion="1.0"; id=$p.pluginName; name=$p.pluginName; version=$version; author=$author; sourceCommit=$sourceCommit; generatedAtUtc=$generatedAt; description=$p.description; capabilities=@($p.description); dependencies=@(); assets=[ordered]@{ agents=$p.assets.agents; instructions=$p.assets.instructions; prompts=$p.assets.prompts; skills=$p.assets.skills } }
  if($p.pluginId -eq "PLG-04"){ $pluginJson.dependencies=@("core-intake-governance","governance-review-audit") }
  elseif($p.pluginId -eq "PLG-03"){ $pluginJson.dependencies=@("core-intake-governance") }
  ($pluginJson | ConvertTo-Json -Depth 8) | Out-File -LiteralPath (Join-Path $pluginRoot "plugin.json") -Encoding utf8

  $files = Get-ChildItem -LiteralPath $pluginRoot -Recurse -File | Where-Object { $_.Name -notin @("manifest.json","README.md","asset-inventory.json","bundle.sha256.json") }
  $entries = foreach($f in $files){ $rel = Rel $pluginRoot $f.FullName; [ordered]@{ path=$rel; sha256=(Get-FileHash -Algorithm SHA256 -LiteralPath $f.FullName).Hash.ToLowerInvariant(); purpose=($p.purposes[$rel] ?? "Plugin asset") } }
  $entries = $entries | Sort-Object path
  $canonical = ($entries | ForEach-Object { "{0}:{1}" -f $_.path,$_.sha256 }) -join "`n"
  $aggBytes = [Text.Encoding]::UTF8.GetBytes($canonical)
  $aggHash = [Security.Cryptography.SHA256]::Create().ComputeHash($aggBytes)
  $aggregateDigest = -join ($aggHash | ForEach-Object { $_.ToString("x2") })

  $manifest = [ordered]@{ pluginId=$p.pluginId; pluginName=$p.pluginName; pluginVersion=$version; author=$author; sourceCommit=$sourceCommit; generatedAtUtc=$generatedAt; digestAlgorithm="SHA-256"; artifactEntries=($entries | ForEach-Object { [ordered]@{ path=$_.path; sha256=$_.sha256 } }); aggregateDigest=$aggregateDigest }
  ($manifest | ConvertTo-Json -Depth 8) | Out-File -LiteralPath (Join-Path $pluginRoot "manifest.json") -Encoding utf8
  ([ordered]@{ pluginId=$p.pluginId; pluginName=$p.pluginName; pluginVersion=$version; generatedAtUtc=$generatedAt; artifactEntries=$entries } | ConvertTo-Json -Depth 8) | Out-File -LiteralPath (Join-Path $pluginRoot "asset-inventory.json") -Encoding utf8

  $zipPath = Join-Path $pluginRoot ("{0}-{1}.zip" -f $p.pluginName,$version)
  if(Test-Path -LiteralPath $zipPath){ Remove-Item -LiteralPath $zipPath -Force }
  $zipSource = @("agents","instructions","prompts","skills","plugin.json","manifest.json","asset-inventory.json") | ForEach-Object { Join-Path $pluginRoot $_ }
  Compress-Archive -Path $zipSource -DestinationPath $zipPath -CompressionLevel Optimal
  $bundleSha = (Get-FileHash -Algorithm SHA256 -LiteralPath $zipPath).Hash.ToLowerInvariant()
  ([ordered]@{ algorithm="SHA-256"; bundleFile=[IO.Path]::GetFileName($zipPath); bundleSha256=$bundleSha } | ConvertTo-Json -Depth 4) | Out-File -LiteralPath (Join-Path $pluginRoot "bundle.sha256.json") -Encoding utf8

  $readmeLines = @(
    "# $($p.pluginName)","","## Overview","",
    "- Plugin ID: $($p.pluginId)","- Plugin Name: $($p.pluginName)","- Semantic Version: $version","- Author: $author","- Source Commit: $sourceCommit","- Generated At (UTC): $generatedAt","- Digest Algorithm: SHA-256","",
    "## Bundle Integrity","","- Bundle File: $([IO.Path]::GetFileName($zipPath))","- Bundle SHA-256: $bundleSha","",
    "## Asset Inventory","","| Asset Path | Purpose | SHA-256 |","|---|---|---|"
  )
  foreach($e in $entries){ $purpose = ($e.purpose -replace "\|","/"); $readmeLines += "| $($e.path) | $purpose | $($e.sha256) |" }
  $readmeLines += @("","## Verification","","1. Validate per-asset hashes from manifest: `Get-FileHash -Algorithm SHA256 -LiteralPath <asset>`.","2. Validate bundle hash: `Get-FileHash -Algorithm SHA256 -LiteralPath ./$([IO.Path]::GetFileName($zipPath))`.","3. Confirm source commit exists: `git cat-file -t $sourceCommit`.")
  [IO.File]::WriteAllLines((Join-Path $pluginRoot "README.md"), $readmeLines)

  $marketEntries += [ordered]@{ pluginId=$p.pluginId; pluginName=$p.pluginName; version=$version; description=$p.description; author=$author; sourceCommit=$sourceCommit; generatedAtUtc=$generatedAt; bundleFile=[IO.Path]::GetFileName($zipPath); bundleSha256=$bundleSha; manifestPath=(Rel $root (Join-Path $pluginRoot "manifest.json")); readmePath=(Rel $root (Join-Path $pluginRoot "README.md")); packagePath=(Rel $root $zipPath) }
}

$marketplace = [ordered]@{ schemaVersion="1.0"; generatedAtUtc=$generatedAt; sourceCommit=$sourceCommit; plugins=$marketEntries }
($marketplace | ConvertTo-Json -Depth 8) | Out-File -LiteralPath (Join-Path $stageRoot "marketplace.json") -Encoding utf8

$marketReadme = @("# Agent Plugins Marketplace Mirror","","This folder mirrors the intended marketplace structure for staged plugin bundles.","","- Generated At (UTC): $generatedAt","- Source Commit: $sourceCommit","- Digest Algorithm: SHA-256","","## Staged Plugins","","| Plugin | Version | Bundle SHA-256 | Bundle File |","|---|---|---|---|")
foreach($m in $marketEntries){ $marketReadme += "| $($m.pluginName) | $($m.version) | $($m.bundleSha256) | $($m.bundleFile) |" }
[IO.File]::WriteAllLines((Join-Path $stageRoot "README.md"), $marketReadme)

Write-Output "Generated plugins: $($marketEntries.pluginName -join ", ")"
Write-Output "Marketplace index: .artifacts/agent-plugins/marketplace.json"
